import React, { useState, useEffect, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom"; // Import useParams
import Webcam from "react-webcam";
import axios from "../api/axios";

const StudyRoom = () => {
    const { id } = useParams(); // Capture the task ID from the URL
    const navigate = useNavigate();
    const webcamRef = useRef(null);

    const [seconds, setSeconds] = useState(3); // 25 mins
    const [isActive, setIsActive] = useState(false);
    const [showQuiz, setShowQuiz] = useState(false);
    const [userAnswer, setUserAnswer] = useState("");

    useEffect(() => {
        let interval = null;
        if (isActive && seconds > 0) {
            interval = setInterval(() => setSeconds(prev => prev - 1), 1000);
        } else if (seconds === 0) {
            clearInterval(interval);
            setIsActive(false);
            setShowQuiz(true); // Auto-show explanation when time hits 0
        }
        return () => clearInterval(interval);
    }, [isActive, seconds]);

    const handleFinalSubmit = async () => {
        if (userAnswer.length < 5) {
            alert("Please provide a summary of your session.");
            return;
        }

        try {
            // 1. Update the backend status using the ID from params
            // Make sure your backend route is /api/tasks/:id
            await axios.patch(`/tasks/${id}`, {
                status: "completed",
                userExplanation: userAnswer
            });
            
            // 2. Redirect to Plan Page after successful update
            navigate("/planPage");
        } catch (error) {
            console.error("Redirect/Update failed:", error);
            // Fallback: Redirect even if API fails so the user isn't stuck
            navigate("/planPage");
        }
    };

    return (
        <div style={{ textAlign: 'center', padding: '20px' }}>
            {!showQuiz ? (
                <>
                    <div style={{ width: '400px', margin: '0 auto', borderRadius: '10px', overflow: 'hidden' }}>
                        <Webcam audio={false} ref={webcamRef} width="100%" />
                    </div>
                    <h1 style={{ fontSize: '4rem' }}>
                        {Math.floor(seconds / 60)}:{String(seconds % 60).padStart(2, '0')}
                    </h1>
                    <button onClick={() => setIsActive(!isActive)}>
                        {isActive ? 'Pause' : 'Start Session'}
                    </button>
                </>
            ) : (
                <div>
                    <h3>Session Complete! Summarize what you learned:</h3>
                    <textarea 
                        value={userAnswer}
                        onChange={(e) => setUserAnswer(e.target.value)}
                        style={{ width: '80%', height: '100px' }}
                    />
                    <br />
                    <button onClick={handleFinalSubmit} style={{ background: 'green', color: 'white' }}>
                        Finish & Go to Plan
                    </button>
                </div>
            )}
        </div>
    );
};

export default StudyRoom;
